import { createContext, useCallback, useContext, useEffect, useState, type ReactNode } from "react";
import * as api from "./endpoints";
import { clearTokens, getStoredUser, storeTokens } from "./tokens";
import type { TokenUser } from "./types";

interface AuthCtx {
  user: TokenUser | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (username: string, password: string) => Promise<void>;
  bootstrap: (username: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  refreshMe: () => Promise<void>;
}

const Ctx = createContext<AuthCtx | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<TokenUser | null>(() => getStoredUser());
  const [isLoading, setIsLoading] = useState<boolean>(() => !!getStoredUser());

  const refreshMe = useCallback(async () => {
    try {
      const res = await api.me();
      setUser({
        user_id: res.user_id,
        username: res.username,
        role: res.role as TokenUser["role"],
        status: res.status as TokenUser["status"],
      });
    } catch {
      setUser(null);
      clearTokens();
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (getStoredUser()) {
      refreshMe();
    } else {
      setIsLoading(false);
    }
  }, [refreshMe]);

  const login = useCallback(async (username: string, password: string) => {
    const env = await api.login(username, password);
    storeTokens(env);
    setUser(env.user);
  }, []);

  const bootstrap = useCallback(async (username: string, password: string) => {
    const env = await api.bootstrap(username, password);
    storeTokens(env);
    setUser(env.user);
  }, []);

  const logout = useCallback(async () => {
    try {
      await api.logout();
    } catch {
      /* ignore */
    }
    clearTokens();
    setUser(null);
  }, []);

  return (
    <Ctx.Provider
      value={{ user, isAuthenticated: !!user, isLoading, login, bootstrap, logout, refreshMe }}
    >
      {children}
    </Ctx.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(Ctx);
  if (!ctx) throw new Error("useAuth must be used inside AuthProvider");
  return ctx;
}

import { clearTokens, getAccessToken, getRefreshToken, storeTokens } from "./tokens";
import type { TokenEnvelope } from "./types";

const DEFAULT_API_BASE_URL = "/api/v1";

function trimTrailingSlash(value: string): string {
  return value.endsWith("/") ? value.slice(0, -1) : value;
}

export const API_BASE_URL: string = trimTrailingSlash(
  (import.meta.env.VITE_API_BASE_URL as string | undefined)?.trim() || DEFAULT_API_BASE_URL,
);

export class ApiError extends Error {
  status: number;
  detail: string;
  constructor(status: number, detail: string) {
    super(detail || `HTTP ${status}`);
    this.status = status;
    this.detail = detail;
  }
}

interface RequestOptions {
  method?: string;
  query?: Record<string, string | number | boolean | null | undefined>;
  body?: unknown;
  rawBody?: BodyInit | null;
  headers?: Record<string, string>;
  auth?: boolean;
  signal?: AbortSignal;
}

let refreshInFlight: Promise<string | null> | null = null;

async function performRefresh(): Promise<string | null> {
  const refresh = getRefreshToken();
  if (!refresh) return null;
  try {
    const res = await fetch(`${API_BASE_URL}/auth/refresh`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ refresh_token: refresh }),
    });
    if (!res.ok) {
      clearTokens();
      return null;
    }
    const env = (await res.json()) as TokenEnvelope;
    storeTokens(env);
    return env.access_token;
  } catch {
    clearTokens();
    return null;
  }
}

function buildUrl(path: string, query?: RequestOptions["query"]): string {
  let url: URL;
  if (path.startsWith("http://") || path.startsWith("https://")) {
    url = new URL(path);
  } else if (API_BASE_URL.startsWith("http://") || API_BASE_URL.startsWith("https://")) {
    url = new URL(`${API_BASE_URL}${path}`);
  } else {
    const origin = typeof window !== "undefined" ? window.location.origin : "http://localhost";
    url = new URL(`${API_BASE_URL}${path}`, origin);
  }

  if (query) {
    for (const [k, v] of Object.entries(query)) {
      if (v === undefined || v === null) continue;
      url.searchParams.set(k, String(v));
    }
  }
  return url.toString();
}

export async function apiFetch<T>(path: string, opts: RequestOptions = {}): Promise<T> {
  const { method = "GET", query, body, rawBody, headers = {}, auth = true, signal } = opts;
  const url = buildUrl(path, query);

  const doFetch = async (token: string | null): Promise<Response> => {
    const finalHeaders: Record<string, string> = { ...headers };
    if (auth && token) finalHeaders["Authorization"] = `Bearer ${token}`;
    let finalBody: BodyInit | null | undefined = rawBody;
    if (body !== undefined && rawBody === undefined) {
      finalHeaders["Content-Type"] = finalHeaders["Content-Type"] ?? "application/json";
      finalBody = JSON.stringify(body);
    }
    return fetch(url, { method, headers: finalHeaders, body: finalBody, signal });
  };

  let token = auth ? getAccessToken() : null;
  let res = await doFetch(token);

  if (res.status === 401 && auth) {
    refreshInFlight = refreshInFlight ?? performRefresh();
    const newToken = await refreshInFlight;
    refreshInFlight = null;
    if (newToken) {
      res = await doFetch(newToken);
    }
  }

  if (!res.ok) {
    let detail = `HTTP ${res.status}`;
    try {
      const data = await res.json();
      detail = typeof data?.detail === "string" ? data.detail : JSON.stringify(data);
    } catch {
      /* ignore */
    }
    throw new ApiError(res.status, detail);
  }

  const ctype = res.headers.get("content-type") ?? "";
  if (ctype.includes("application/json")) return (await res.json()) as T;
  // fallback: return blob for binary
  return (await res.blob()) as unknown as T;
}

export async function apiFetchBlob(path: string, opts: RequestOptions = {}): Promise<Blob> {
  return apiFetch<Blob>(path, opts);
}

import { createContext, useContext, useMemo, useState, type ReactNode } from "react";
import { Crown, Calculator, FileSpreadsheet, Eye } from "lucide-react";
import { useAuth } from "./api/auth";
import type { BackendRole } from "./api/types";

export type Role = "admin" | "actuaire" | "sinistres" | "auditeur";

export interface RoleInfo {
  key: Role;
  label: string;
  user: string;
  icon: typeof Crown;
  description: string;
}

export const ROLES: Record<Role, RoleInfo> = {
  admin: {
    key: "admin",
    label: "Direction",
    user: "M. Hadj",
    icon: Crown,
    description: "Vue exécutive · validation · audit global",
  },
  actuaire: {
    key: "actuaire",
    label: "Actuaire",
    user: "S. Boukerma",
    icon: Calculator,
    description: "Méthodes · triangulation · IBNR · hypothèses",
  },
  sinistres: {
    key: "sinistres",
    label: "Sinistres",
    user: "K. Lounis",
    icon: FileSpreadsheet,
    description: "Dossiers · PSAP · règlements",
  },
  auditeur: {
    key: "auditeur",
    label: "Auditeur",
    user: "F. Mansouri",
    icon: Eye,
    description: "Lecture seule · traçabilité · exports validés",
  },
};

// Map backend roles onto the existing UI roles (keeps the visual role selector working).
const BACKEND_TO_UI: Record<BackendRole, Role> = {
  ADMIN: "admin",
  HR: "actuaire",
  VIEWER: "auditeur",
};

interface Ctx {
  role: Role;
  setRole: (r: Role) => void;
  info: RoleInfo;
  can: (action: "edit" | "validate" | "export" | "import" | "viewAudit") => boolean;
}

const RoleContext = createContext<Ctx | null>(null);

export function RoleProvider({ children }: { children: ReactNode }) {
  const auth = useAuth();
  const [manualRole, setManualRole] = useState<Role | null>(null);

  const role: Role = useMemo(() => {
    if (manualRole) return manualRole;
    if (auth?.user) return BACKEND_TO_UI[auth.user.role] ?? "auditeur";
    return "admin";
  }, [manualRole, auth?.user]);

  const info: RoleInfo = useMemo(() => {
    const base = ROLES[role];
    if (auth?.user && !manualRole) {
      return { ...base, user: auth.user.username };
    }
    return base;
  }, [role, auth?.user, manualRole]);

  const can = (action: Parameters<Ctx["can"]>[0]) => {
    const matrix: Record<Role, Record<typeof action, boolean>> = {
      admin: { edit: true, validate: true, export: true, import: true, viewAudit: true },
      actuaire: { edit: true, validate: false, export: true, import: true, viewAudit: true },
      sinistres: { edit: true, validate: false, export: true, import: false, viewAudit: false },
      auditeur: { edit: false, validate: false, export: true, import: false, viewAudit: true },
    };
    return matrix[role][action];
  };

  return (
    <RoleContext.Provider value={{ role, setRole: setManualRole, info, can }}>
      {children}
    </RoleContext.Provider>
  );
}

export function useRole() {
  const ctx = useContext(RoleContext);
  if (!ctx) throw new Error("useRole must be used inside RoleProvider");
  return ctx;
}

