        <h1 className="text-2xl font-bold tracking-tight text-foreground">Something went wrong</h1>
        <p className="mt-2 text-sm text-muted-foreground">
          An unexpected error occurred. Please try again.
        </p>
        {import.meta.env.DEV && error.message && (
          <pre className="mt-4 max-h-40 overflow-auto rounded-md bg-muted p-3 text-left font-mono text-xs text-destructive">
            {error.message}
          </pre>
        )}
        <div className="mt-6 flex items-center justify-center gap-3">
          <button
            onClick={() => {
              router.invalidate();
              reset();
            }}
            className="inline-flex items-center justify-center rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90"
          >
            Try again
          </button>
          <a
            href="/"
            className="inline-flex items-center justify-center rounded-md border border-input bg-background px-4 py-2 text-sm font-medium text-foreground transition-colors hover:bg-accent"
          >
            Go home
          </a>
        </div>
      </div>
    </div>
  );
}

export const getRouter = () => {
  const router = createRouter({
    routeTree,
    context: {},
    scrollRestoration: true,
    defaultPreloadStaleTime: 0,
    defaultErrorComponent: DefaultErrorComponent,
  });

  return router;
};

import { createFileRoute, Link, notFound } from "@tanstack/react-router";
import { Topbar } from "@/components/layout/Topbar";
import { KpiCard, SectionCard, Badge } from "@/components/ui/kpi-card";
import { useMemo } from "react";
import { useDashboardSummary, useRunRows } from "@/lib/api/queries";
import { toIbnrSummary, toPpnaSummary, toSapSummary } from "@/lib/api/runRows";
import { buildBackendProducts } from "@/lib/backendProducts";
import { ChevronLeft, FileText, Layers, ShieldAlert, TrendingUp } from "lucide-react";
import {
  ResponsiveContainer,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  RadialBarChart,
  RadialBar,
  PolarAngleAxis,
} from "recharts";

export const Route = createFileRoute("/app/produits/$productKey")({
  head: ({ params }) => {
    return { meta: [{ title: `${params.productKey} — L'Algérienne Vie` }] };
  },
  component: ProductDetail,
  notFoundComponent: () => (
    <div className="p-12 text-center">
      <h1 className="font-display text-2xl mb-2">Produit introuvable</h1>
      <Link to="/app/produits" className="text-primary">
        Retour aux produits
      </Link>
    </div>
  ),
});

const fmtMDA = (valueInDa: number) =>
  (valueInDa / 1_000_000).toLocaleString("fr-FR", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }) + " M DA";

const fmtPct = (value: number) => `${(value * 100).toFixed(1)} %`;

function ProductDetail() {
  const { productKey } = Route.useParams();

  const summaryQuery = useDashboardSummary();
  const runIds = {
    ppna: summaryQuery.data?.domains?.ppna?.run_id ?? null,
    sap: summaryQuery.data?.domains?.sap?.run_id ?? null,
    ibnr: summaryQuery.data?.domains?.ibnr?.run_id ?? null,
  };

  const ppnaRows = useRunRows<unknown[]>("ppna", runIds.ppna);
  const sapRows = useRunRows<unknown[]>("sap", runIds.sap);
  const ibnrRows = useRunRows<unknown>("ibnr", runIds.ibnr);

  const ppna = useMemo(() => toPpnaSummary(ppnaRows.data), [ppnaRows.data]);
  const sap = useMemo(() => toSapSummary(sapRows.data), [sapRows.data]);
  const ibnr = useMemo(() => toIbnrSummary(ibnrRows.data), [ibnrRows.data]);

  const products = useMemo(() => buildBackendProducts(ppna, sap, ibnr), [ibnr, ppna, sap]);
  const product = products.find((item) => item.slug === productKey);
  const isLoading =
    summaryQuery.isLoading || ppnaRows.isLoading || sapRows.isLoading || ibnrRows.isLoading;

  if (isLoading && !product) {
    return (
      <>
        <Topbar title="Produit" subtitle="Chargement des agrégats backend" />
        <div className="p-6 lg:p-8">
          <div className="rounded-md border border-border bg-card px-4 py-3 text-sm text-muted-foreground">
            Chargement des données produit depuis le backend...
          </div>
        </div>
      </>
    );
  }

  if (!product) throw notFound();

  const productSapRows = sap.rows.filter((row) => row.product === product.name);

  const trend = useMemo(() => {
    const byYear = new Map<string, { declared: number; sap: number }>();
    for (const row of productSapRows) {
      const year = /^\d{4}/.test(row.declarationDate) ? row.declarationDate.slice(0, 4) : "N/A";
      const current = byYear.get(year) ?? { declared: 0, sap: 0 };
      current.declared += row.declaredAmount;
      current.sap += row.sapAmount;
      byYear.set(year, current);
    }
    return Array.from(byYear.entries())
      .map(([year, values]) => ({
        year,
        declared: +(values.declared / 1_000_000).toFixed(3),
        sap: +(values.sap / 1_000_000).toFixed(3),
      }))
      .sort((a, b) => a.year.localeCompare(b.year));
  }, [productSapRows]);

  const lossRatio = product.premiums > 0 ? product.sap / product.premiums : 0;
  const ratio = [
    {
      name: "S/P",
      value: lossRatio * 100,
      fill:
        lossRatio < 0.6
          ? "var(--success)"
          : lossRatio < 0.85
            ? "var(--gold)"
            : "var(--destructive)",
    },
  ];

  const networkBreakdown = useMemo(() => {
    const map = new Map<string, number>();
    for (const row of productSapRows) {
      map.set(row.network, (map.get(row.network) ?? 0) + 1);
    }
    return Array.from(map.entries())
      .map(([name, dossiers]) => ({ name, dossiers }))
      .sort((a, b) => b.dossiers - a.dossiers);
  }, [productSapRows]);

  return (
    <>
      <Topbar title={product.name} subtitle="Vue produit dérivée des runs backend" />
      <div className="p-6 lg:p-8 space-y-6">
        <Link
          to="/app/produits"
          className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground"
        >
          <ChevronLeft className="h-4 w-4" /> Toutes les branches
        </Link>

        <div className="bg-gradient-primary text-white rounded-lg p-6 lg:p-8 flex items-start gap-5 shadow-elegant">
          <div className="h-16 w-16 rounded-md bg-white/10 backdrop-blur flex items-center justify-center border border-white/20">
            <span className="font-display text-3xl text-gold">
              {product.name.slice(0, 1).toUpperCase()}
            </span>
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-[10px] tracking-[0.22em] uppercase text-gold mb-1">
              Backend aggregé
            </div>
            <h2 className="font-display text-2xl mb-1">{product.name}</h2>
            <p className="text-white/70 text-sm max-w-2xl">
              Données consolidées à partir des sorties PPNA / SAP / IBNR. Aucun modèle frontend
              local.
            </p>
          </div>
          <Badge variant="gold">Actif</Badge>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <KpiCard
            label="Dossiers SAP"
            value={product.claimCount.toLocaleString("fr-FR")}
            hint="Source SAP"
            icon={<FileText className="h-4 w-4" />}
            accent="primary"
          />
          <KpiCard
            label="Primes"
            value={fmtMDA(product.premiums)}
            icon={<Layers className="h-4 w-4" />}
          />
          <KpiCard
            label="SAP"
            value={fmtMDA(product.sap)}
            hint={`S/P ${fmtPct(lossRatio)}`}
            icon={<ShieldAlert className="h-4 w-4" />}
            accent="gold"
          />
          <KpiCard
            label="Réserves techniques"
            value={fmtMDA(product.reserveTotal)}
            hint="PPNA + SAP + IBNR"
            icon={<TrendingUp className="h-4 w-4" />}
          />
        </div>

        <div className="grid lg:grid-cols-3 gap-6">
          <SectionCard
            className="lg:col-span-2"
            title="Déclaré vs SAP"
            description="Vue annuelle extraite des lignes SAP du produit"
          >
            <ResponsiveContainer width="100%" height={260}>
              <AreaChart data={trend} margin={{ top: 5, right: 10, left: -10, bottom: 0 }}>
                <defs>
                  <linearGradient id="pp" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="var(--chart-1)" stopOpacity={0.4} />
                    <stop offset="95%" stopColor="var(--chart-1)" stopOpacity={0.02} />
                  </linearGradient>
                  <linearGradient id="ss" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="var(--gold)" stopOpacity={0.4} />
                    <stop offset="95%" stopColor="var(--gold)" stopOpacity={0.02} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false} />
                <XAxis
                  dataKey="year"
                  stroke="var(--muted-foreground)"
                  fontSize={11}
                  tickLine={false}
                  axisLine={false}
                />
                <YAxis
                  stroke="var(--muted-foreground)"
                  fontSize={11}
                  tickLine={false}
                  axisLine={false}
                />
                <Tooltip
                  contentStyle={{
                    background: "var(--card)",
                    border: "1px solid var(--border)",
                    borderRadius: 8,
                    fontSize: 12,
                  }}
                />
                <Area
                  type="monotone"
                  dataKey="declared"
                  stroke="var(--chart-1)"
                  fill="url(#pp)"
                  strokeWidth={2}
                  name="Déclaré"
                />
                <Area
                  type="monotone"
                  dataKey="sap"
                  stroke="var(--gold)"
                  fill="url(#ss)"
                  strokeWidth={2}
                  name="SAP"
                />
              </AreaChart>
            </ResponsiveContainer>
          </SectionCard>

          <SectionCard title="Loss ratio" description="Cible technique < 85%">
            <ResponsiveContainer width="100%" height={200}>
              <RadialBarChart
                innerRadius="65%"
                outerRadius="100%"
                data={ratio}
                startAngle={90}
                endAngle={-270}
              >
                <PolarAngleAxis type="number" domain={[0, 100]} tick={false} />
                <RadialBar background dataKey="value" cornerRadius={6} />
              </RadialBarChart>
            </ResponsiveContainer>
            <div className="text-center -mt-32 mb-12 pointer-events-none">
              <div className="font-display text-4xl text-foreground">{fmtPct(lossRatio)}</div>
              <div className="text-xs text-muted-foreground tracking-wide uppercase mt-1">
                S / P
              </div>
            </div>
          </SectionCard>
        </div>

        <div className="grid lg:grid-cols-2 gap-6">
          <SectionCard
            title="Répartition par réseau"
            description="Nombre de dossiers SAP par réseau"
          >
            <div className="space-y-4">
              {networkBreakdown.map((network, i) => {
                const max = Math.max(...networkBreakdown.map((x) => x.dossiers));
                const w = max > 0 ? (network.dossiers / max) * 100 : 0;
                return (
                  <div key={network.name}>
                    <div className="flex justify-between text-sm mb-1.5">
                      <span className="text-foreground font-medium">{network.name}</span>
                      <span className="text-muted-foreground">
                        {network.dossiers.toLocaleString("fr-FR")} dossiers
                      </span>
                    </div>
                    <div className="h-2 bg-muted rounded-full overflow-hidden">
                      <div
                        className="h-full bg-gradient-gold rounded-full transition-all"
                        style={{ width: `${w}%`, opacity: 1 - i * 0.2 }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          </SectionCard>

          <SectionCard title="Indicateurs techniques" description="Hypothèses et ratios produit">
            <dl className="divide-y divide-border">
              {[
                ["Loss ratio (S/P)", fmtPct(lossRatio)],
                ["Primes", fmtMDA(product.premiums)],
                ["PPNA", fmtMDA(product.ppna)],
                ["SAP", fmtMDA(product.sap)],
                ["IBNR", fmtMDA(product.ibnr)],
                ["Réseaux observés", product.networks.length.toString()],
              ].map(([k, v]) => (
                <div key={k} className="flex justify-between py-3 text-sm">
                  <dt className="text-muted-foreground">{k}</dt>
                  <dd className="font-medium text-foreground">{v}</dd>
                </div>
              ))}
            </dl>
          </SectionCard>
        </div>
      </div>
    </>
  );
}

import { Link, createFileRoute } from "@tanstack/react-router";
import { Topbar } from "@/components/layout/Topbar";
import { KpiCard, SectionCard, Badge } from "@/components/ui/kpi-card";
import { Calculator, Download } from "lucide-react";
import { useMemo, useState } from "react";
import { useDashboardSummary, useRun } from "@/lib/api/queries";
import type { Domain } from "@/lib/api/types";

export const Route = createFileRoute("/app/provisions")({
  head: () => ({ meta: [{ title: "Modules de provisionnement — L'Algérienne Vie" }] }),
  component: ProvisionsPage,
});

const fmtMDA = (valueInDa: number) =>
  (valueInDa / 1_000_000).toLocaleString("fr-FR", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }) + " M DA";

interface ProvisionModule {
  key: Domain;
  name: string;
  full: string;
  formula: string;
  inputs: string[];
  value: number;
  badge: "validé" | "en cours" | "à démarrer";
  runId: string | null;
  parameters: Record<string, unknown>;
}

const MODULE_METADATA: Record<
  Domain,
  Omit<ProvisionModule, "value" | "badge" | "runId" | "parameters">
> = {
  ppna: {
    key: "ppna",
    name: "PPNA",
    full: "Provision pour Primes Non Acquises",
    formula:
      "contract_days = (echeance - effet) + 1 ; remaining_days = IF(cloture<effet OR cloture>echeance, 0, echeance-cloture) ; PPNA = net_premium * remaining_days / contract_days",
    inputs: ["net_premium", "effect_date", "expiry_date", "closing_date"],
  },
  sap: {
    key: "sap",
    name: "SAP",
    full: "Provision pour Sinistres À Payer",
    formula:
      "if closing_date < declaration_date => 0 ; if declaration_date < closing_date < settlement_notification_date => declared_amount ; else: status REJET => 0, status SAP => declared_amount, otherwise max(0, declared_amount - paid_amount)",
    inputs: [
      "declaration_date",
      "settlement_notification_date",
      "declared_amount",
      "paid_amount",
      "status",
      "closing_date",
    ],
  },
  ibnr: {
    key: "ibnr",
    name: "IBNR",
    full: "Incurred But Not Reported",
    formula:
      "F[j] = SUM(C[i,j]) / SUM(C[i,j-1]) ; projection C[i,j] = F[j] * C[i,j-1] ; reserve_i = ultimate_i - diagonal_i ; IBNR = SUM(reserve_i)",
    inputs: [
      "occurrence_year",
      "declaration_year",
      "claim_amount",
      "closing_year",
      "occurrence_year_window",
    ],
  },
  pe: {
    key: "pe",
    name: "PE",
    full: "Provision d'Égalisation",
    formula:
      "historical_average = (claims_charge_n1 + claims_charge_n2 + claims_charge_n3) / 3 ; component_pos = max(0, technical_result) * positive_result_coefficient ; component_hist = historical_average * historical_average_coefficient ; PE = technical_result>0 ? min(component_pos, component_hist) : 0",
    inputs: [
      "technical_result",
      "claims_charge_n1",
      "claims_charge_n2",
      "claims_charge_n3",
      "positive_result_coefficient",
      "historical_average_coefficient",
    ],
  },
  pb: {
    key: "pb",
    name: "PB",
    full: "Participation aux Bénéfices",
    formula:
      "total_credit = premiums_n + rec_opening + sap_opening ; management_fee_amount = management_fee_rate * premiums_n ; total_debit = claims_paid_n + prec_closing + sap_closing + management_fee_amount + prior_debit_carryover ; credit_balance = total_credit - total_debit ; PB = (loss_ratio<=threshold AND credit_balance>0) ? pb_rate*credit_balance : 0",
    inputs: [
      "premiums_n",
      "rec_opening",
      "sap_opening",
      "claims_paid_n",
      "prec_closing",
      "sap_closing",
      "management_fee_rate",
      "prior_debit_carryover",
      "loss_ratio",
      "loss_ratio_threshold",
      "pb_rate",
    ],
  },
};

function ProvisionsPage() {
  const summaryQuery = useDashboardSummary();
  const runIds = {
    ppna: summaryQuery.data?.domains?.ppna?.run_id ?? null,
    sap: summaryQuery.data?.domains?.sap?.run_id ?? null,
    pe: summaryQuery.data?.domains?.pe?.run_id ?? null,
    pb: summaryQuery.data?.domains?.pb?.run_id ?? null,
    ibnr: summaryQuery.data?.domains?.ibnr?.run_id ?? null,
  };

  const ppnaRun = useRun("ppna", runIds.ppna);
  const sapRun = useRun("sap", runIds.sap);
  const peRun = useRun("pe", runIds.pe);
  const pbRun = useRun("pb", runIds.pb);
  const ibnrRun = useRun("ibnr", runIds.ibnr);

  const runByDomain = {
    ppna: ppnaRun.data,
    sap: sapRun.data,
    pe: peRun.data,
    pb: pbRun.data,
    ibnr: ibnrRun.data,
  } as const;

  const modules = useMemo<ProvisionModule[]>(() => {
    return (["ppna", "sap", "ibnr", "pe", "pb"] as Domain[]).map((domain) => {
      const metadata = MODULE_METADATA[domain];
      const slot = summaryQuery.data?.domains?.[domain];
      const run = runByDomain[domain];
      return {
        ...metadata,
        value: slot?.total ?? 0,
        badge: slot ? "validé" : "à démarrer",
        runId: slot?.run_id ?? null,
        parameters: (run?.parameters ?? {}) as Record<string, unknown>,
      };
    });
  }, [
    summaryQuery.data?.domains,
    runByDomain.ibnr,
    runByDomain.pb,
    runByDomain.pe,
    runByDomain.ppna,
    runByDomain.sap,
  ]);

  const [active, setActive] = useState<Domain>("ppna");
  const m = modules.find((item) => item.key === active) ?? modules[0];

  const total = modules.reduce((sum, module) => sum + module.value, 0);
  const hasAnyRun = modules.some((module) => module.runId);

  return (
    <>
      <Topbar
        title="Modules de provisionnement"
        subtitle="Sept modules techniques · formules, hypothèses, sorties"
      />
      <div className="p-6 lg:p-8 space-y-6">
        {!hasAnyRun && !summaryQuery.isLoading && (
          <SectionCard
            title="Aucun run disponible"
            description="Lancez les calculs backend pour alimenter cette vue"
          >
            <p className="text-sm text-muted-foreground">
              Les montants et paramètres affichés ici proviennent exclusivement des runs backend.
            </p>
            <Link
              to="/app/import"
              className="mt-3 inline-block text-sm text-primary underline underline-offset-4"
            >
              Aller à l'import des documents
            </Link>
          </SectionCard>
        )}

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <KpiCard
            label="PPNA"
            value={fmtMDA(modules.find((x) => x.key === "ppna")?.value ?? 0)}
            accent="primary"
            icon={<Calculator className="h-4 w-4" />}
          />
          <KpiCard
            label="SAP"
            value={fmtMDA(modules.find((x) => x.key === "sap")?.value ?? 0)}
            icon={<Calculator className="h-4 w-4" />}
          />
          <KpiCard
            label="IBNR"
            value={fmtMDA(modules.find((x) => x.key === "ibnr")?.value ?? 0)}
            accent="gold"
            icon={<Calculator className="h-4 w-4" />}
          />
          <KpiCard
            label="PE + PB"
            value={fmtMDA(
              (modules.find((x) => x.key === "pe")?.value ?? 0) +
                (modules.find((x) => x.key === "pb")?.value ?? 0),
            )}
            icon={<Calculator className="h-4 w-4" />}
          />
        </div>

        <div className="grid lg:grid-cols-12 gap-6">
          {/* Tabs */}
          <div className="lg:col-span-3">
            <div className="bg-card border border-border rounded-lg overflow-hidden shadow-soft">
              {modules.map((mod) => (
                <button
                  key={mod.key}
                  onClick={() => setActive(mod.key)}
                  className={`w-full text-left px-4 py-3 border-b border-border last:border-0 transition-colors ${
                    active === mod.key ? "bg-primary/5 border-l-2 border-l-gold" : "hover:bg-muted"
                  }`}
                >
                  <div className="text-sm font-medium text-foreground">{mod.name}</div>
                  <div className="text-[11px] text-muted-foreground">{mod.full}</div>
                </button>
              ))}
            </div>
          </div>

          {/* Detail */}
          <div className="lg:col-span-9 space-y-6">
            <SectionCard
              title={`${m.name} · ${m.full}`}
              description="Formule backend, entrées requises et sortie courante"
              action={
                <div className="flex items-center gap-2">
                  <Badge
                    variant={
                      m.badge === "validé" ? "success" : m.badge === "en cours" ? "warning" : "info"
                    }
                  >
                    {m.badge}
                  </Badge>
                  <button className="inline-flex items-center gap-1.5 text-xs bg-gradient-primary text-white px-3 py-1.5 rounded-md hover:shadow-elegant">
                    <Download className="h-3 w-3" /> Export
                  </button>
                </div>
              }
            >
              <div className="grid lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 space-y-5">
                  <div>
                    <div className="text-[10px] tracking-[0.18em] uppercase text-muted-foreground mb-2">
                      Formule
                    </div>
                    <div className="bg-primary/5 border border-primary/10 rounded-md p-4 font-mono text-sm text-primary leading-relaxed">
                      {m.formula}
                    </div>
                  </div>
                  <div>
                    <div className="text-[10px] tracking-[0.18em] uppercase text-muted-foreground mb-2">
                      Entrées requises
                    </div>
                    <ul className="grid sm:grid-cols-2 gap-2">
                      {m.inputs.map((inp) => (
                        <li
                          key={inp}
                          className="flex items-center gap-2 text-sm text-foreground bg-muted/40 rounded-md px-3 py-2"
                        >
                          <span className="h-1.5 w-1.5 rounded-full bg-gold" /> {inp}
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
                <div className="bg-gradient-primary text-white rounded-md p-5 flex flex-col justify-between">
                  <div className="text-[10px] tracking-[0.22em] uppercase text-gold mb-2">
                    Sortie T4-2024
                  </div>
                  <div>
                    <div className="font-display text-4xl">{fmtMDA(m.value)}</div>
                    <div className="text-xs text-white/60 mt-2">
                      Run: {m.runId ?? "non disponible"}
                    </div>
                  </div>
                  <div className="mt-4 border-t border-white/20 pt-3">
                    <div className="text-[10px] tracking-[0.18em] uppercase text-white/70 mb-1">
                      Paramètres
                    </div>
                    <div className="text-[11px] text-white/80 break-words">
                      {Object.keys(m.parameters).length === 0
                        ? "(paramètres par défaut)"
                        : JSON.stringify(m.parameters)}
                    </div>
                  </div>
                </div>
              </div>
            </SectionCard>

            <SectionCard
              title="Contribution par module"
              description="Part de chaque module dans le total backend"
            >
              <div className="space-y-3">
                {modules.map((module) => {
                  const share = total > 0 ? module.value / total : 0;
                  return (
                    <div key={module.key}>
                      <div className="flex justify-between text-sm mb-1.5">
                        <span className="text-foreground">{module.name}</span>
                        <span className="font-medium text-foreground">
                          {fmtMDA(module.value)}{" "}
                          <span className="text-muted-foreground text-xs ml-1">
                            ({(share * 100).toFixed(1)}%)
                          </span>
                        </span>
                      </div>
                      <div className="h-1.5 bg-muted rounded-full overflow-hidden">
                        <div
                          className="h-full bg-gradient-gold rounded-full"
                          style={{ width: `${Math.max(share * 100, 2)}%` }}
                        />
                      </div>
                    </div>
                  );
                })}
              </div>
            </SectionCard>
          </div>
        </div>
      </div>
    </>
  );
}

import { Link, createFileRoute } from "@tanstack/react-router";
import { Topbar } from "@/components/layout/Topbar";
import { SectionCard, Badge } from "@/components/ui/kpi-card";
import { useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useDashboardSummary, useRunRows } from "@/lib/api/queries";
import { toIbnrSummary } from "@/lib/api/runRows";
import { downloadRunArtifact } from "@/lib/api/endpoints";
import { Download, ToggleLeft, ToggleRight } from "lucide-react";

export const Route = createFileRoute("/app/triangles")({
  head: () => ({ meta: [{ title: "Triangulation — L'Algérienne Vie" }] }),
  component: TrianglesPage,
});

interface TriangleCellPayload {
  occurrence_year: number;
  development_year: number;
  incremental_amount: number;
  cumulative_amount: number;
}

interface DevelopmentFactorPayload {
  development_year: number;
  factor: number;
}

interface IbnrResultArtifact {
  triangle_cells?: TriangleCellPayload[];
  development_factors?: DevelopmentFactorPayload[];
}

const fmtM = (v: number) =>
  v === 0
    ? "—"
    : (v / 1_000_000).toLocaleString("fr-FR", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }) + " M DA";

function TrianglesPage() {
  const summaryQuery = useDashboardSummary();
  const runId = summaryQuery.data?.domains?.ibnr?.run_id ?? null;
  const rowsQuery = useRunRows<unknown>("ibnr", runId);

  const artifactQuery = useQuery({
    queryKey: ["ibnr", "result-artifact", runId],
    enabled: Boolean(runId),
    queryFn: async () => {
      const blob = await downloadRunArtifact("ibnr", runId as string, "result.json");
      const text = await blob.text();
      return JSON.parse(text) as IbnrResultArtifact;
    },
  });

  const ibnrSummary = useMemo(() => toIbnrSummary(rowsQuery.data), [rowsQuery.data]);
  const [cumulative, setCumulative] = useState(true);

  const triangleCells = artifactQuery.data?.triangle_cells ?? [];

  const occurrenceYears = useMemo(
    () =>
      Array.from(new Set(triangleCells.map((cell) => cell.occurrence_year))).sort((a, b) => a - b),
    [triangleCells],
  );

  const maxDevelopmentYear = useMemo(
    () => triangleCells.reduce((max, cell) => Math.max(max, cell.development_year), 0),
    [triangleCells],
  );

  const matrix = useMemo(() => {
    const cellMap = new Map<string, TriangleCellPayload>();
    for (const cell of triangleCells) {
      cellMap.set(`${cell.occurrence_year}-${cell.development_year}`, cell);
    }
    return occurrenceYears.map((year) => {
      const values: Array<number | null> = [];
      for (let dev = 0; dev <= maxDevelopmentYear; dev += 1) {
        const cell = cellMap.get(`${year}-${dev}`);
        if (!cell) {
          values.push(null);
          continue;
        }
        values.push(cumulative ? cell.cumulative_amount : cell.incremental_amount);
      }
      return values;
    });
  }, [cumulative, maxDevelopmentYear, occurrenceYears, triangleCells]);

  const flat = matrix.flat().filter((v): v is number => typeof v === "number");
  const min = flat.length > 0 ? Math.min(...flat) : 0;
  const max = flat.length > 0 ? Math.max(...flat) : 0;

  const colorFor = (v: number) => {
    const t = (v - min) / (max - min || 1);
    return `oklch(${0.96 - t * 0.18} ${0.04 + t * 0.08} 75)`;
  };

  const factorMap = useMemo(() => {
    const map = new Map<number, number>();
    for (const factor of artifactQuery.data?.development_factors ?? []) {
      map.set(factor.development_year, factor.factor);
    }
    return map;
  }, [artifactQuery.data?.development_factors]);

  const ultimates = ibnrSummary.mergedRows.map((row) => ({
    year: row.occurrenceYear,
    known: row.diagonal,
    ultimate: row.ultimate,
    ibnr: row.reserve,
  }));

  const isLoading =
    summaryQuery.isLoading || (Boolean(runId) && (rowsQuery.isLoading || artifactQuery.isLoading));
  const hasData = ultimates.length > 0;

  return (
    <>
      <Topbar
        title="Triangulation des sinistres"
        subtitle="Développement cumulé · base Chain Ladder"
      />
      <div className="p-6 lg:p-8 space-y-6">
        {!runId && (
          <SectionCard
            title="Aucun run IBNR disponible"
            description="Importez un document IBNR puis lancez un calcul backend"
          >
            <p className="text-sm text-muted-foreground">
              Cette page n'utilise plus de triangle local: seules les données backend sont
              affichées.
            </p>
            <Link
              to="/app/import"
              className="mt-3 inline-block text-sm text-primary underline underline-offset-4"
            >
              Aller à l'import des documents
            </Link>
          </SectionCard>
        )}

        {runId && (rowsQuery.isError || artifactQuery.isError) && (
          <SectionCard
            title="Erreur de chargement"
            description="Impossible de récupérer les résultats IBNR backend"
          >
            <p className="text-sm text-danger-foreground">
              {rowsQuery.error instanceof Error
                ? rowsQuery.error.message
                : artifactQuery.error instanceof Error
                  ? artifactQuery.error.message
                  : "Erreur inconnue"}
            </p>
          </SectionCard>
        )}

        {isLoading && (
          <SectionCard
            title="Chargement"
            description="Récupération du triangle depuis les artefacts backend"
          >
            <p className="text-sm text-muted-foreground">Veuillez patienter...</p>
          </SectionCard>
        )}

        {runId && hasData && !rowsQuery.isError && !artifactQuery.isError && !isLoading && (
          <>
            <div className="flex flex-wrap items-center gap-3">
              <Badge variant="info">Branche : Toutes</Badge>
              <Badge variant="default">Devise : DZD (M)</Badge>
              <Badge variant="default">
                Année inventaire : {String(summaryQuery.data?.domains?.ibnr?.finished_at ?? "run")}
              </Badge>
              <button
                onClick={() => setCumulative(!cumulative)}
                className="ml-auto inline-flex items-center gap-2 text-sm bg-card border border-border px-3 py-1.5 rounded-md hover:border-gold/40 transition-colors"
              >
                {cumulative ? (
                  <ToggleRight className="h-4 w-4 text-gold" />
                ) : (
                  <ToggleLeft className="h-4 w-4 text-muted-foreground" />
                )}
                {cumulative ? "Cumulé" : "Incrémental"}
              </button>
              <button className="inline-flex items-center gap-2 text-sm bg-gradient-primary text-white px-3 py-1.5 rounded-md hover:shadow-elegant transition-all">
                <Download className="h-4 w-4" /> Export
              </button>
            </div>

            <SectionCard
              title="Triangle de développement"
              description={`${cumulative ? "Cumulé" : "Incrémental"} · ${occurrenceYears.length} années × ${maxDevelopmentYear + 1} développements`}
            >
              <div className="overflow-x-auto -mx-6 px-6">
                <table className="text-xs border-separate border-spacing-1">
                  <thead>
                    <tr>
                      <th className="px-3 py-2 text-left text-muted-foreground tracking-wider uppercase text-[10px] font-medium">
                        Origine
                      </th>
                      {Array.from({ length: maxDevelopmentYear + 1 }).map((_, j) => (
                        <th
                          key={j}
                          className="px-3 py-2 text-center text-muted-foreground tracking-wider uppercase text-[10px] font-medium min-w-[80px]"
                        >
                          Dév {j}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {matrix.map((row, i) => (
                      <tr key={occurrenceYears[i]}>
                        <td className="px-3 py-2 font-medium text-foreground">
                          {occurrenceYears[i]}
                        </td>
                        {row.map((v, j) => (
                          <td
                            key={j}
                            className="px-3 py-2 text-center rounded-md font-mono"
                            style={
                              v == null
                                ? {
                                    background: "var(--muted)",
                                    color: "var(--muted-foreground)",
                                    fontStyle: "italic",
                                  }
                                : { background: colorFor(v), color: "var(--foreground)" }
                            }
                          >
                            {v == null ? "—" : v.toLocaleString("fr-FR")}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="border-t-2 border-border">
                      <td className="px-3 pt-3 font-medium text-gold-deep">Facteurs</td>
                      {Array.from({ length: maxDevelopmentYear + 1 }).map((_, j) => {
                        const f = j === 0 ? null : (factorMap.get(j) ?? null);
                        return (
                          <td key={j} className="px-3 pt-3 text-center font-mono text-gold-deep">
                            {f == null ? "—" : f.toFixed(3)}
                          </td>
                        );
                      })}
                    </tr>
                  </tfoot>
                </table>
              </div>
            </SectionCard>

            <SectionCard
              title="Projection des ultimes"
              description="Charge ultime estimée par année d'origine (méthode Chain Ladder)"
            >
              <div className="overflow-x-auto -mx-6">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-[11px] tracking-wider uppercase text-muted-foreground border-b border-border bg-muted/30">
                      <th className="text-left font-medium px-6 py-2">Année</th>
                      <th className="text-right font-medium px-6 py-2">Cumulé observé</th>
                      <th className="text-right font-medium px-6 py-2">Ultime projeté</th>
                      <th className="text-right font-medium px-6 py-2">IBNR</th>
                      <th className="text-right font-medium px-6 py-2">% IBNR</th>
                    </tr>
                  </thead>
                  <tbody>
                    {ultimates.map((u) => (
                      <tr
                        key={u.year}
                        className="border-b border-border last:border-0 hover:bg-muted/30"
                      >
                        <td className="px-6 py-3 font-medium text-foreground">{u.year}</td>
                        <td className="px-6 py-3 text-right font-mono text-foreground">
                          {fmtM(u.known)}
                        </td>
                        <td className="px-6 py-3 text-right font-mono font-semibold text-foreground">
                          {fmtM(u.ultimate)}
                        </td>
                        <td className="px-6 py-3 text-right font-mono text-gold-deep font-semibold">
                          {fmtM(u.ibnr)}
                        </td>
                        <td className="px-6 py-3 text-right text-muted-foreground">
                          {u.ultimate === 0 ? "—" : `${((u.ibnr / u.ultimate) * 100).toFixed(1)}%`}
                        </td>
                      </tr>
                    ))}
                    <tr className="bg-primary/5 border-t-2 border-border">
                      <td className="px-6 py-3 font-display text-base text-foreground">Total</td>
                      <td className="px-6 py-3 text-right font-mono text-foreground">
                        {fmtM(ultimates.reduce((s, u) => s + u.known, 0))}
                      </td>
                      <td className="px-6 py-3 text-right font-mono font-bold text-foreground">
                        {fmtM(ultimates.reduce((s, u) => s + u.ultimate, 0))}
                      </td>
                      <td className="px-6 py-3 text-right font-mono font-bold text-gold-deep">
                        {fmtM(ultimates.reduce((s, u) => s + u.ibnr, 0))}
                      </td>
                      <td className="px-6 py-3"></td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </SectionCard>
          </>
        )}
      </div>
    </>
  );
}
